#include <bits/stdc++.h>
using namespace std;

int getCount(int N) {
    int count = 0;

    // L represents length of consecutive sequence minus 1
    for(int L = 1; L * (L + 1) < 2 * N; L++) {
        // Find first number in sequence (a)
        // For sequence a, a+1, a+2, ..., a+L:
        // N = a(L+1) + L(L+1)/2
        // Therefore: a = (N - L(L+1)/2)/(L+1)
        double a = (1.0 * N - (L * (L + 1)) / 2) / (L + 1);

        // If 'a' is a positive integer, we found a valid sequence
        if(a > 0 && a == (int)a) {
            count++;
        }
    }

    return count;
}

int main() {
    int T;
    cin >> T;

    while(T--) {
        int N;
        cin >> N;
        cout << getCount(N) << endl;
    }
    return 0;
}
